// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract PostingBoard {
    struct Post {
        address author;
        string content;
        uint256 totalPower;
    }

    mapping(uint256 => Post) private postsById;
    mapping(address => uint256) private authorBalances;
    uint256 public postCount;

    event PostCreated(uint256 indexed postId, address indexed author, string content);
    event PostBoosted(uint256 indexed postId, uint256 amount);
    event Withdrawal(address indexed author, uint256 amount);

    function createPost(string calldata content) external returns (uint256) {
        require(bytes(content).length > 0, "Content cannot be empty");
        uint256 newPostId = postCount++;
        postsById[newPostId] = Post({
            author: msg.sender,
            content: content,
            totalPower: 0
        });
        emit PostCreated(newPostId, msg.sender, content);
        return newPostId;
    }

    function boostPost(uint256 postId) external payable {
        require(postId < postCount, "Post does not exist");
        require(msg.value > 0, "Must send ether to boost");
        Post storage post = postsById[postId];
        require(post.author == msg.sender, "Only author can boost");
        post.totalPower += msg.value;
        authorBalances[post.author] += msg.value;
        emit PostBoosted(postId, msg.value);
    }

    function getAuthorBalances(address _author) external view returns (uint256) {
        return authorBalances[_author];
    }

    function posts(uint256 _postId) public view returns (address author, string memory content, uint256 totalPower) {
        Post storage post = postsById[_postId];
        return (post.author, post.content, post.totalPower);
    }

    function withdraw() external {
        uint256 amount = authorBalances[msg.sender];
        authorBalances[msg.sender] = 0;
        (bool sent,) = payable(msg.sender).call{value: amount}("");
        require(sent, "Failed to send Ether");
        emit Withdrawal(msg.sender, amount);
    }
}
